// ============================================================================
// Thiele CPU — Synthesis Wrapper (Kami-proven ISA, synthesizable arrays)
// ============================================================================
//
// Generated by: scripts/kami_verilog_synth_transform.py
//
// This module implements the EXACT SAME ISA as the Kami-extracted
// thiele_cpu_kami.v (simulation golden model), but uses proper Verilog
// arrays for storage instead of flat bit-vectors.
//
// Correctness guarantee: co-simulation tests verify bit-exact match
// between this module and the Kami-extracted version.
//
// Instruction encoding: [31:24] opcode | [23:16] op_a | [15:8] op_b | [7:0] cost
//
// ============================================================================

`ifdef BSV_ASSIGNMENT_DELAY
`else
  `define BSV_ASSIGNMENT_DELAY
`endif

`ifdef BSV_POSITIVE_RESET
  `define BSV_RESET_VALUE 1'b1
  `define BSV_RESET_EDGE posedge
`else
  `define BSV_RESET_VALUE 1'b0
  `define BSV_RESET_EDGE negedge
`endif

module mkModule1(CLK,
         RST_N,

         loadInstr_x_0,
         EN_loadInstr,
         RDY_loadInstr,

         EN_getPC,
         getPC,
         RDY_getPC,

         EN_getMu,
         getMu,
         RDY_getMu,

         EN_getErr,
         getErr,
         RDY_getErr,

         EN_getHalted,
         getHalted,
         RDY_getHalted,

         EN_getPartitionOps,
         getPartitionOps,
         RDY_getPartitionOps,

         EN_getMdlOps,
         getMdlOps,
         RDY_getMdlOps,

         EN_getInfoGain,
         getInfoGain,
         RDY_getInfoGain,

         EN_getErrorCode,
         getErrorCode,
         RDY_getErrorCode,

         EN_getMuTensor0,
         getMuTensor0,
         RDY_getMuTensor0,

         EN_getMuTensor1,
         getMuTensor1,
         RDY_getMuTensor1,

         EN_getMuTensor2,
         getMuTensor2,
         RDY_getMuTensor2,

         EN_getMuTensor3,
         getMuTensor3,
         RDY_getMuTensor3,

         EN_getBianchiAlarm,
         getBianchiAlarm,
         RDY_getBianchiAlarm);

  input  CLK;
  input  RST_N;

  // loadInstr: {addr[39:32], data[31:0]}
  input  [39 : 0] loadInstr_x_0;
  input  EN_loadInstr;
  output RDY_loadInstr;

  input  EN_getPC;
  output [31 : 0] getPC;
  output RDY_getPC;

  input  EN_getMu;
  output [31 : 0] getMu;
  output RDY_getMu;

  input  EN_getErr;
  output getErr;
  output RDY_getErr;

  input  EN_getHalted;
  output getHalted;
  output RDY_getHalted;

  input  EN_getPartitionOps;
  output [31 : 0] getPartitionOps;
  output RDY_getPartitionOps;

  input  EN_getMdlOps;
  output [31 : 0] getMdlOps;
  output RDY_getMdlOps;

  input  EN_getInfoGain;
  output [31 : 0] getInfoGain;
  output RDY_getInfoGain;

  input  EN_getErrorCode;
  output [31 : 0] getErrorCode;
  output RDY_getErrorCode;

  input  EN_getMuTensor0;
  output [31 : 0] getMuTensor0;
  output RDY_getMuTensor0;

  input  EN_getMuTensor1;
  output [31 : 0] getMuTensor1;
  output RDY_getMuTensor1;

  input  EN_getMuTensor2;
  output [31 : 0] getMuTensor2;
  output RDY_getMuTensor2;

  input  EN_getMuTensor3;
  output [31 : 0] getMuTensor3;
  output RDY_getMuTensor3;

  input  EN_getBianchiAlarm;
  output getBianchiAlarm;
  output RDY_getBianchiAlarm;

  // Ready signals: always ready
  assign RDY_loadInstr      = 1'd1;
  assign RDY_getPC           = 1'd1;
  assign RDY_getMu           = 1'd1;
  assign RDY_getErr          = 1'd1;
  assign RDY_getHalted       = 1'd1;
  assign RDY_getPartitionOps = 1'd1;
  assign RDY_getMdlOps       = 1'd1;
  assign RDY_getInfoGain     = 1'd1;
  assign RDY_getErrorCode    = 1'd1;
  assign RDY_getMuTensor0    = 1'd1;
  assign RDY_getMuTensor1    = 1'd1;
  assign RDY_getMuTensor2    = 1'd1;
  assign RDY_getMuTensor3    = 1'd1;
  assign RDY_getBianchiAlarm = 1'd1;

  // ========================================================================
  // STORAGE: proper arrays (synthesis-friendly)
  // ========================================================================

  reg [31:0] pc;
  reg [31:0] mu;
  reg        err;
  reg        halted;
  reg [31:0] regs      [0:31];    // 32 registers
  reg [31:0] mem       [0:255];   // 256-word data memory
  reg [31:0] imem      [0:255];   // 256-word instruction memory
  reg [31:0] partition_ops;
  reg [31:0] mdl_ops;
  reg [31:0] info_gain;
  reg [31:0] error_code;
  reg [31:0] mu_tensor [0:15];    // 4x4 flattened tensor

  // ========================================================================
  // OPCODES (matches Coq/Python ISA exactly)
  // ========================================================================

  localparam [7:0] OP_PNEW         = 8'h00;
  localparam [7:0] OP_PSPLIT       = 8'h01;
  localparam [7:0] OP_PMERGE       = 8'h02;
  localparam [7:0] OP_LASSERT      = 8'h03;
  localparam [7:0] OP_LJOIN        = 8'h04;
  localparam [7:0] OP_MDLACC       = 8'h05;
  localparam [7:0] OP_PDISCOVER    = 8'h06;
  localparam [7:0] OP_XFER         = 8'h07;
  localparam [7:0] OP_LOAD_IMM     = 8'h08;
  localparam [7:0] OP_CHSH_TRIAL   = 8'h09;
  localparam [7:0] OP_XOR_LOAD     = 8'h0A;
  localparam [7:0] OP_XOR_ADD      = 8'h0B;
  localparam [7:0] OP_XOR_SWAP     = 8'h0C;
  localparam [7:0] OP_XOR_RANK     = 8'h0D;
  localparam [7:0] OP_EMIT         = 8'h0E;
  localparam [7:0] OP_REVEAL       = 8'h0F;
  localparam [7:0] OP_ORACLE_HALTS = 8'h10;
  localparam [7:0] OP_LOAD         = 8'h11;
  localparam [7:0] OP_STORE        = 8'h12;
  localparam [7:0] OP_ADD          = 8'h13;
  localparam [7:0] OP_SUB          = 8'h14;
  localparam [7:0] OP_JUMP         = 8'h15;
  localparam [7:0] OP_JNEZ         = 8'h16;
  localparam [7:0] OP_CALL         = 8'h17;
  localparam [7:0] OP_RET          = 8'h18;
  localparam [7:0] OP_HALT         = 8'hFF;

  // Error codes
  localparam [31:0] ERR_BIANCHI_VAL = 32'hb1a4c81;
  localparam [31:0] ERR_CHSH_VAL    = 32'hbadc45c;

  // ========================================================================
  // OUTPUT PORTS
  // ========================================================================

  assign getPC           = pc;
  assign getMu           = mu;
  assign getErr          = err;
  assign getHalted       = halted;
  assign getPartitionOps = partition_ops;
  assign getMdlOps       = mdl_ops;
  assign getInfoGain     = info_gain;
  assign getErrorCode    = error_code;

  // Tensor row sums
  assign getMuTensor0 = mu_tensor[0]  + mu_tensor[1]  + mu_tensor[2]  + mu_tensor[3];
  assign getMuTensor1 = mu_tensor[4]  + mu_tensor[5]  + mu_tensor[6]  + mu_tensor[7];
  assign getMuTensor2 = mu_tensor[8]  + mu_tensor[9]  + mu_tensor[10] + mu_tensor[11];
  assign getMuTensor3 = mu_tensor[12] + mu_tensor[13] + mu_tensor[14] + mu_tensor[15];

  // Bianchi conservation alarm
  wire [31:0] tensor_total =
    mu_tensor[0]  + mu_tensor[1]  + mu_tensor[2]  + mu_tensor[3]  +
    mu_tensor[4]  + mu_tensor[5]  + mu_tensor[6]  + mu_tensor[7]  +
    mu_tensor[8]  + mu_tensor[9]  + mu_tensor[10] + mu_tensor[11] +
    mu_tensor[12] + mu_tensor[13] + mu_tensor[14] + mu_tensor[15];
  assign getBianchiAlarm = (tensor_total > mu);

  // ========================================================================
  // FETCH + DECODE (combinational)
  // ========================================================================

  wire [31:0] instr      = imem[pc[7:0]];
  wire [7:0]  opcode     = instr[31:24];
  wire [7:0]  op_a       = instr[23:16];
  wire [7:0]  op_b       = instr[15:8];
  wire [7:0]  cost_v     = instr[7:0];
  wire [31:0] cost32     = {24'd0, cost_v};
  wire [31:0] new_mu     = mu + cost32;
  wire [31:0] pc_plus_1  = pc + 32'd1;

  // Register indices
  wire [4:0] dst_idx     = op_a[4:0];
  wire [4:0] src_idx     = op_b[4:0];
  wire [4:0] rs1_idx     = {1'b0, op_b[7:4]};
  wire [4:0] rs2_idx     = {1'b0, op_b[3:0]};

  // Register reads
  wire [31:0] rs1_val    = regs[rs1_idx];
  wire [31:0] rs2_val    = regs[rs2_idx];
  wire [31:0] dst_val    = regs[dst_idx];
  wire [31:0] src_val    = regs[src_idx];
  wire [31:0] sp_val     = regs[31];  // r31 = SP

  // Memory reads
  wire [31:0] mem_val    = mem[op_b[7:0]];
  wire [31:0] ret_pc_val = mem[sp_val[7:0] - 8'd1];

  // ALU results
  wire [31:0] add_result = rs1_val + rs2_val;
  wire [31:0] sub_result = rs1_val - rs2_val;
  wire [31:0] xor_result = dst_val ^ src_val;
  wire        jnez_taken = (dst_val != 32'd0);

  // Jump/call target
  wire [31:0] jump_target = {16'd0, op_a, op_b};
  wire [31:0] jnez_target = {24'd0, op_b};

  // Popcount (tree-based, matches Kami extraction)
  wire [31:0] pop_v      = src_val;
  wire [31:0] pop_m1     = 32'h55555555;
  wire [31:0] pop_s1     = (pop_v & pop_m1) + ((pop_v >> 1) & pop_m1);
  wire [31:0] pop_m2     = 32'h33333333;
  wire [31:0] pop_s2     = (pop_s1 & pop_m2) + ((pop_s1 >> 2) & pop_m2);
  wire [31:0] pop_m3     = 32'h0f0f0f0f;
  wire [31:0] pop_s3     = (pop_s2 & pop_m3) + ((pop_s2 >> 4) & pop_m3);
  wire [31:0] pop_m4     = 32'h00ff00ff;
  wire [31:0] pop_s4     = (pop_s3 & pop_m4) + ((pop_s3 >> 8) & pop_m4);
  wire [31:0] popcount   = (pop_s4 + (pop_s4 >> 16)) & 32'h0000ffff;

  // CHSH validation
  wire chsh_bits_bad = (op_a > 8'd1) || (op_b > 8'd1);

  // Bianchi violation check
  wire bianchi_viol = (tensor_total > mu);

  // Partition op detection
  wire is_partition_op = (opcode == OP_PNEW) || (opcode == OP_PSPLIT) || (opcode == OP_PMERGE);
  wire is_info_gain_op = (opcode == OP_PDISCOVER) || (opcode == OP_EMIT);

  // REVEAL tensor index
  wire [3:0] tensor_idx = op_a[3:0];

  // ========================================================================
  // STEP RULE (posedge CLK) — matches Kami atomic step exactly
  // ========================================================================

  always @(posedge CLK) begin
    if (RST_N == `BSV_RESET_VALUE) begin
      // Reset all state
      pc             <= `BSV_ASSIGNMENT_DELAY 32'd0;
      mu             <= `BSV_ASSIGNMENT_DELAY 32'd0;
      err            <= `BSV_ASSIGNMENT_DELAY 1'b0;
      halted         <= `BSV_ASSIGNMENT_DELAY 1'b0;
      partition_ops  <= `BSV_ASSIGNMENT_DELAY 32'd0;
      mdl_ops        <= `BSV_ASSIGNMENT_DELAY 32'd0;
      info_gain      <= `BSV_ASSIGNMENT_DELAY 32'd0;
      error_code     <= `BSV_ASSIGNMENT_DELAY 32'd0;
      begin : reset_arrays
        integer ri;
        for (ri = 0; ri < 32; ri = ri + 1)  regs[ri]      <= `BSV_ASSIGNMENT_DELAY 32'd0;
        for (ri = 0; ri < 256; ri = ri + 1) mem[ri]       <= `BSV_ASSIGNMENT_DELAY 32'd0;
        for (ri = 0; ri < 256; ri = ri + 1) imem[ri]      <= `BSV_ASSIGNMENT_DELAY 32'd0;
        for (ri = 0; ri < 16; ri = ri + 1)  mu_tensor[ri] <= `BSV_ASSIGNMENT_DELAY 32'd0;
      end
    end else begin
      // loadInstr method: write one instruction word
      if (EN_loadInstr)
        imem[loadInstr_x_0[39:32]] <= `BSV_ASSIGNMENT_DELAY loadInstr_x_0[31:0];

      // Step rule: only fires when !halted && !err
      if (!halted && !err) begin
        // Bianchi violation: freeze CPU
        if (bianchi_viol) begin
          halted     <= `BSV_ASSIGNMENT_DELAY 1'b1;
          error_code <= `BSV_ASSIGNMENT_DELAY ERR_BIANCHI_VAL;
          // pc and mu unchanged
        end else begin
          // Charge mu (always, for every instruction)
          mu <= `BSV_ASSIGNMENT_DELAY new_mu;

          // Halted on HALT
          if (opcode == OP_HALT)
            halted <= `BSV_ASSIGNMENT_DELAY 1'b1;

          // Error on bad CHSH bits
          if ((opcode == OP_CHSH_TRIAL) && chsh_bits_bad) begin
            err        <= `BSV_ASSIGNMENT_DELAY 1'b1;
            error_code <= `BSV_ASSIGNMENT_DELAY ERR_CHSH_VAL;
          end

          // ── PC update ──
          case (opcode)
            OP_HALT:  pc <= `BSV_ASSIGNMENT_DELAY pc;  // stay
            OP_JUMP:  pc <= `BSV_ASSIGNMENT_DELAY jump_target;
            OP_CALL:  pc <= `BSV_ASSIGNMENT_DELAY jump_target;
            OP_RET:   pc <= `BSV_ASSIGNMENT_DELAY ret_pc_val;
            OP_JNEZ:  pc <= `BSV_ASSIGNMENT_DELAY (jnez_taken ? jnez_target : pc_plus_1);
            default:  pc <= `BSV_ASSIGNMENT_DELAY pc_plus_1;
          endcase

          // ── Register file write ──
          case (opcode)
            OP_LOAD_IMM: regs[dst_idx] <= `BSV_ASSIGNMENT_DELAY {24'd0, op_b};
            OP_ADD:      regs[dst_idx] <= `BSV_ASSIGNMENT_DELAY add_result;
            OP_SUB:      regs[dst_idx] <= `BSV_ASSIGNMENT_DELAY sub_result;
            OP_XFER:     regs[dst_idx] <= `BSV_ASSIGNMENT_DELAY src_val;
            OP_LOAD:     regs[dst_idx] <= `BSV_ASSIGNMENT_DELAY mem_val;
            OP_XOR_LOAD: regs[dst_idx] <= `BSV_ASSIGNMENT_DELAY mem_val;
            OP_XOR_ADD:  regs[dst_idx] <= `BSV_ASSIGNMENT_DELAY xor_result;
            OP_XOR_SWAP: begin
              regs[dst_idx] <= `BSV_ASSIGNMENT_DELAY src_val;
              regs[src_idx] <= `BSV_ASSIGNMENT_DELAY dst_val;
            end
            OP_XOR_RANK: regs[dst_idx] <= `BSV_ASSIGNMENT_DELAY popcount;
            OP_CALL:     regs[31]      <= `BSV_ASSIGNMENT_DELAY (sp_val + 32'd1);
            OP_RET:      regs[31]      <= `BSV_ASSIGNMENT_DELAY (sp_val - 32'd1);
            default: ;  // no register write
          endcase

          // ── Memory write ──
          case (opcode)
            OP_STORE: mem[op_a] <= `BSV_ASSIGNMENT_DELAY src_val;
            OP_CALL:  mem[sp_val[7:0]] <= `BSV_ASSIGNMENT_DELAY pc_plus_1;
            default: ;
          endcase

          // ── Counter updates ──
          if (is_partition_op)
            partition_ops <= `BSV_ASSIGNMENT_DELAY partition_ops + 32'd1;
          if (opcode == OP_MDLACC)
            mdl_ops <= `BSV_ASSIGNMENT_DELAY mdl_ops + 32'd1;
          if (is_info_gain_op)
            info_gain <= `BSV_ASSIGNMENT_DELAY info_gain + {24'd0, op_b};

          // ── Tensor update (REVEAL) ──
          if (opcode == OP_REVEAL)
            mu_tensor[tensor_idx] <= `BSV_ASSIGNMENT_DELAY mu_tensor[tensor_idx] + cost32;

        end  // !bianchi_viol
      end  // !halted && !err
    end  // !reset
  end

  // synopsys translate_off
  `ifdef BSV_NO_INITIAL_BLOCKS
  `else
  initial begin
    begin : init_arrays
      integer ii;
      pc = 32'hAAAAAAAA;
      mu = 32'hAAAAAAAA;
      err = 1'b0;
      halted = 1'b0;
      partition_ops = 32'hAAAAAAAA;
      mdl_ops = 32'hAAAAAAAA;
      info_gain = 32'hAAAAAAAA;
      error_code = 32'hAAAAAAAA;
      for (ii = 0; ii < 32; ii = ii + 1)  regs[ii]      = 32'hAAAAAAAA;
      for (ii = 0; ii < 256; ii = ii + 1) mem[ii]       = 32'hAAAAAAAA;
      for (ii = 0; ii < 256; ii = ii + 1) imem[ii]      = 32'hAAAAAAAA;
      for (ii = 0; ii < 16; ii = ii + 1)  mu_tensor[ii] = 32'hAAAAAAAA;
    end
  end
  `endif
  // synopsys translate_on

endmodule  // mkModule1
